 14→/// Prune `required` entries that reference properties not defined in `properties`.
 15→///
 16→/// MCP tools (e.g. Home Assistant with 80+ tools) may declare `required`
 17→/// entries for properties defined via unsupported keywords (`dependentSchemas`,
 18→/// `if`/`then`/`else`, `patternProperties`) that get stripped by
 19→/// `OpenAiSchemaSubsetTransform`. Gemini strictly validates that every
 20→/// `required` entry has a matching property and rejects the request with
 21→/// "property is not defined" when they don't match (issue #747).
 22→#[derive(Debug, Clone, Default)]
 23→struct PruneOrphanedRequiredTransform;
 24→
 25→impl Transform for PruneOrphanedRequiredTransform {
 26→    fn transform(&mut self, schema: &mut Schema) {
 27→        let Some(obj) = schema.as_object_mut() else {
 28→            return;
 29→        };
 30→
 31→        // Collect property names that have a meaningful schema.  Properties
 32→        // with bare boolean schemas (`true`) or empty objects (`{}`) are
 33→        // treated as undefined because:
 34→        //  - canonicalization adds `true` (the "accept anything" schema) for
 35→        //    orphaned `required` entries
 36→        //  - keyword stripping can reduce a property to `{}` when all its
 37→        //    keywords were unsupported
 38→        // In both cases the property has no usable type information and Gemini
 39→        // rejects it with "property is not defined" (issue #747).
 40→        let defined_props: BTreeSet<String> = obj
 41→            .get("properties")
 42→            .and_then(|v| v.as_object())
 43→            .map(|props| {
 44→                props
 45→                    .iter()
 46→                    .filter(|(_, v)| {
 47→                        v.as_bool().is_none() && !v.as_object().is_some_and(|o| o.is_empty())
 48→                    })
 49→                    .map(|(k, _)| k.clone())
 50→                    .collect()
 51→            })
 52→            .unwrap_or_default();
 53→
 54→        if defined_props.is_empty() {
 55→            // No usable properties — `required` is entirely orphaned.
 56→            obj.remove("required");
 57→            return;
 58→        }
 59→
 60→        if let Some(required) = obj.get_mut("required").and_then(|v| v.as_array_mut()) {
 61→            required.retain(|entry| {
 62→                entry
 63→                    .as_str()
 64→                    .is_some_and(|name| defined_props.contains(name))
 65→            });
 66→        }
 67→        // Remove `required` entirely when retain emptied it.
 68→        if obj
 69→            .get("required")
 70→            .and_then(|v| v.as_array())
 71→            .is_some_and(|a| a.is_empty())
 72→        {
 73→            obj.remove("required");
 74→        }
 75→    }
 76→}
