 78→/// Re-infer `"type"` from `"enum"` values when canonicalization stripped it.
 79→///
 80→/// `json_schema_ast` canonicalization removes redundant `"type"` annotations
 81→/// when all enum values match the declared type (`lower_enum_with_type`), and
 82→/// converts `"type": "boolean"` → `"enum": [false, true]`
 83→/// (`lower_boolean_and_null_types`). This is correct per JSON Schema semantics
 84→/// but providers like Fireworks AI reject schemas without explicit `"type"`.
 85→///
 86→/// This transform walks every schema node and restores `"type"` when:
 87→/// - `"enum"` is present but `"type"` is absent
 88→/// - All non-null enum values share a single JSON type
 89→#[derive(Debug, Clone, Default)]
 90→struct RestoreEnumTypeTransform;
 91→
 92→impl Transform for RestoreEnumTypeTransform {
 93→    fn transform(&mut self, schema: &mut Schema) {
 94→        let Some(obj) = schema.as_object_mut() else {
 95→            return;
 96→        };
 97→
 98→        // Only act when `enum` is present and `type` is absent.
 99→        if obj.contains_key("type") {
100→            return;
101→        }
102→        let Some(values) = obj.get("enum").and_then(|v| v.as_array()) else {
103→            return;
104→        };
105→        if values.is_empty() {
106→            return;
107→        }
108→
109→        // Collect the distinct JSON types of non-null enum values.
110→        let mut types = BTreeSet::new();
111→        for value in values {
112→            match value {
113→                serde_json::Value::Null => {}, // ignore null for type inference
114→                serde_json::Value::Bool(_) => {
115→                    types.insert("boolean");
116→                },
117→                serde_json::Value::Number(n) => {
118→                    if n.is_f64() && !n.is_i64() && !n.is_u64() {
119→                        types.insert("number");
120→                    } else {
121→                        types.insert("integer");
122→                    }
123→                },
124→                serde_json::Value::String(_) => {
125→                    types.insert("string");
126→                },
127→                serde_json::Value::Array(_) => {
128→                    types.insert("array");
129→                },
130→                serde_json::Value::Object(_) => {
131→                    types.insert("object");
132→                },
133→            }
134→        }
135→
136→        // In JSON Schema, "number" subsumes "integer". When both appear
137→        // (e.g. enum mixes 1 and 1.5), collapse to "number".
138→        if types.contains("integer") && types.contains("number") {
139→            types.remove("integer");
140→        }
141→
142→        // Only restore when all non-null values share a single type.
143→        if types.len() == 1 {
144→            let inferred_type = types.into_iter().next().unwrap_or_default();
145→            obj.insert(
146→                "type".to_string(),
147→                serde_json::Value::String(inferred_type.to_string()),
148→            );
149→        }
150→    }
151→}
