153→/// Remove empty `{}` (the JSON Schema "true" schema) from `anyOf`/`oneOf`
154→/// composite arrays and collapse single-variant composites inline.
155→///
156→/// Canonicalization of `not` and other negation keywords produces `{}` (the
157→/// "accepts anything" schema). After keyword stripping, these survive as
158→/// empty objects inside `anyOf`/`oneOf`, which OpenAI rejects with
159→/// "schema must have a 'type' key" (issue #743).
160→#[derive(Debug, Clone, Default)]
161→struct SimplifyCompositeTransform;
162→
163→impl Transform for SimplifyCompositeTransform {
164→    fn transform(&mut self, schema: &mut Schema) {
165→        let Some(obj) = schema.as_object_mut() else {
166→            return;
167→        };
168→
169→        for keyword in ["anyOf", "oneOf", "allOf"] {
170→            let Some(variants) = obj.get_mut(keyword).and_then(|v| v.as_array_mut()) else {
171→                continue;
172→            };
173→
174→            // Drop empty-object variants (`{}`).
175→            variants.retain(|v| !v.as_object().is_some_and(|o| o.is_empty()));
176→
177→            if variants.len() == 1 {
178→                // Single variant left — inline it, replacing the composite.
179→                let single = variants.remove(0);
180→                obj.remove(keyword);
181→                if let serde_json::Value::Object(inner) = single {
182→                    for (k, v) in inner {
183→                        // Parent-key wins: if a key is already present (e.g. `type`
184→                        // from a surrounding object schema), we keep the parent value
185→                        // and discard the variant's. This is safe for the `not`→`{}`
186→                        // canonicalization pattern this transform targets.
187→                        obj.entry(k).or_insert(v);
188→                    }
189→                }
190→            } else if variants.is_empty() {
191→                obj.remove(keyword);
192→            }
193→        }
194→    }
195→}
