229→#[derive(Debug, Clone, Default)]
230→struct OpenAiSchemaSubsetTransform;
231→
232→impl Transform for OpenAiSchemaSubsetTransform {
233→    fn transform(&mut self, schema: &mut Schema) {
234→        let Some(obj) = schema.as_object_mut() else {
235→            return;
236→        };
237→
238→        obj.retain(|key, _| OPENAI_ALLOWED_SCHEMA_KEYWORDS.contains(&key.as_str()));
239→    }
240→}
