242→fn canonicalize_schema_for_openai_compat(schema: &serde_json::Value) -> serde_json::Value {
243→    // Strip `$schema` so `SchemaDocument::from_json()` doesn't reject
244→    // non-2020-12 drafts (e.g. draft-07 from Attio MCP tools, issue #743).
245→    // Draft-07 and 2020-12 share enough structural keywords that
246→    // canonicalization works; remaining differences (`definitions` vs
247→    // `$defs`, tuple `items` vs `prefixItems`) are handled by schemars
248→    // transforms downstream. `$schema` itself is later stripped by
249→    // `OpenAiSchemaSubsetTransform` anyway.
250→    let mut input = schema.clone();
251→    if let Some(obj) = input.as_object_mut() {
252→        obj.remove("$schema");
253→    }
254→
255→    let document = match SchemaDocument::from_json(&input) {
256→        Ok(document) => document,
257→        Err(error) => {
258→            warn!(
259→                error = %error,
260→                "openai tool schema failed Draft 2020-12 preflight; using raw schema for best-effort normalization"
261→            );
262→            return input;
263→        },
264→    };
265→
266→    if let Err(error) = document.root() {
267→        warn!(
268→            error = %error,
269→            "openai tool schema failed canonical AST resolution; using raw schema for best-effort normalization"
270→        );
271→        return input;
272→    }
273→
274→    document
275→        .canonical_schema_json()
276→        .map_or_else(
277→            |error| {
278→                warn!(
279→                    error = %error,
280→                    "openai tool schema canonicalization was unavailable; using raw schema for best-effort normalization"
281→                );
282→                input
283→            },
284→            serde_json::Value::clone,
285→        )
286→}
