288→/// Validate and normalize a JSON Schema document into the OpenAI-compatible
289→/// function-calling subset via `json_schema_ast` canonicalization plus
290→/// recursive `schemars` transforms.
291→pub(crate) fn sanitize_schema_for_openai_compat(schema: &mut serde_json::Value) {
292→    let canonical = canonicalize_schema_for_openai_compat(schema);
293→
294→    let Ok(mut transformed) = Schema::try_from(canonical.clone()) else {
295→        *schema = canonical;
296→        return;
297→    };
298→    let mut replace_const = ReplaceConstValue::default();
299→    replace_const.transform(&mut transformed);
300→    let mut replace_unevaluated_properties = ReplaceUnevaluatedProperties::default();
301→    replace_unevaluated_properties.transform(&mut transformed);
302→    let mut replace_prefix_items = ReplacePrefixItems::default();
303→    replace_prefix_items.transform(&mut transformed);
304→    let mut remove_ref_siblings = RemoveRefSiblings::default();
305→    remove_ref_siblings.transform(&mut transformed);
306→    let mut subset_transform = RecursiveTransform(OpenAiSchemaSubsetTransform);
307→    subset_transform.transform(&mut transformed);
308→
309→    // Strip empty `{}` schemas from anyOf/oneOf (left behind by
310→    // canonicalization of `not` and other negation keywords) and collapse
311→    // single-variant composites inline (issue #743).
312→    let mut simplify_composite = RecursiveTransform(SimplifyCompositeTransform);
313→    simplify_composite.transform(&mut transformed);
314→
315→    // Prune `required` entries that reference properties not defined in
316→    // `properties`. Keyword stripping above can remove property definitions
317→    // (e.g. `dependentSchemas`, `if/then/else`) while leaving their names
318→    // in `required`. Gemini rejects such schemas (issue #747).
319→    let mut prune_orphaned_required = RecursiveTransform(PruneOrphanedRequiredTransform);
320→    prune_orphaned_required.transform(&mut transformed);
321→
322→    // Re-infer `"type"` from enum values after canonicalization stripped it.
323→    // Providers like Fireworks AI reject schemas without explicit type
324→    // annotations even when enum values unambiguously imply the type.
325→    let mut restore_enum_type = RecursiveTransform(RestoreEnumTypeTransform);
326→    restore_enum_type.transform(&mut transformed);
327→
328→    *schema = transformed.to_value();
329→}
