 73→/// Check whether a schema's `type` field designates an object.
 74→///
 75→/// Matches both `"type": "object"` and `"type": ["object", ...]`.
 76→/// Downstream providers like Gemini cannot represent type arrays, and OpenAI
 77→/// strict mode requires `type` to be a single string.
 78→fn type_is_object(obj: &serde_json::Map<String, serde_json::Value>) -> bool {
 79→    let Some(ty) = obj.get("type") else {
 80→        return false;
 81→    };
 82→
 83→    match ty {
 84→        serde_json::Value::String(kind) => kind == "object",
 85→        serde_json::Value::Array(kinds) => kinds.iter().any(|kind| kind.as_str() == Some("object")),
 86→        _ => false,
 87→    }
 88→}
