  9→        "tool_calls": [{
 10→            "id": "call_1",
 11→            "function": {
 12→                "name": "grep",
 13→                "arguments": {
 14→                    "offset": 0,
 15→                    "multiline": false,
 16→                    "type": null
 17→                }
 18→            }
 19→        }]
 20→    });
 21→
 22→    let calls = parse_tool_calls(&msg);
 23→
 24→    assert_eq!(calls.len(), 1);
 25→    assert_eq!(calls[0].arguments["offset"], 0);
 26→    assert_eq!(calls[0].arguments["multiline"], false);
 27→    assert!(calls[0].arguments["type"].is_null());
