812→/// Issue #743: MCP tools declaring `$schema: "http://json-schema.org/draft-07/schema#"`
813→/// (e.g. Attio) bypass canonicalization entirely because `SchemaDocument::from_json()`
814→/// only accepts Draft 2020-12. Without canonicalization, stripping `not` leaves
815→/// empty `{}` schemas inside `anyOf` which OpenAI rejects ("schema must have a
816→/// 'type' key"). The sanitizer must strip `$schema` before canonicalization so
817→/// that draft-07 schemas get the same AST resolution as draft 2020-12.
818→#[test]
819→fn sanitize_draft07_schema_strips_unsupported_keywords() {
820→    // Reproduces the Attio MCP schema pattern from issue #743:
821→    // nested anyOf with `not` and no `type` key, declared as draft-07.
822→    let mut schema = serde_json::json!({
823→        "$schema": "http://json-schema.org/draft-07/schema#",
824→        "type": "object",
825→        "properties": {
826→            "query": {
827→                "anyOf": [
828→                    {
829→                        "anyOf": [
830→                            {
831→                                "not": {
832→                                    "const": ""
833→                                }
834→                            },
835→                            {
836→                                "type": "string"
837→                            }
838→                        ]
839→                    },
840→                    {
841→                        "type": "null"
842→                    }
843→                ]
844→            }
845→        }
846→    });
847→
848→    sanitize_schema_for_openai_compat(&mut schema);
849→    let encoded = schema.to_string();
850→
851→    // `$schema` must be stripped.
852→    assert!(
853→        !encoded.contains("$schema"),
854→        "$schema should be removed, got: {encoded}"
855→    );
856→    // `not` must be stripped.
857→    assert!(
858→        !encoded.contains("\"not\""),
859→        "\"not\" should be removed from draft-07 schema, got: {encoded}"
860→    );
861→
862→    // Critical assertion: no empty `{}` schemas left inside anyOf variants.
863→    // Without canonicalization, stripping `not` leaves `{}` which OpenAI
864→    // rejects with "schema must have a 'type' key".
865→    assert!(
866→        !encoded.contains("{}"),
867→        "empty schemas should not remain after sanitization, got: {encoded}"
868→    );
869→    // The root `type: object` must survive.
870→    assert_eq!(schema["type"], "object");
871→}
