812→/// Issue #743: MCP tools declaring `$schema: "http://json-schema.org/draft-07/schema#"`
813→/// (e.g. Attio) bypass canonicalization entirely because `SchemaDocument::from_json()`
814→/// only accepts Draft 2020-12. Without canonicalization, stripping `not` leaves
815→/// empty `{}` schemas inside `anyOf` which OpenAI rejects ("schema must have a
816→/// 'type' key"). The sanitizer must strip `$schema` before canonicalization so
817→/// that draft-07 schemas get the same AST resolution as draft 2020-12.
818→#[test]
819→fn sanitize_draft07_schema_strips_unsupported_keywords() {
820→    // Reproduces the Attio MCP schema pattern from issue #743:
821→    // nested anyOf with `not` and no `type` key, declared as draft-07.
822→    let mut schema = serde_json::json!({
823→        "$schema": "http://json-schema.org/draft-07/schema#",
824→        "type": "object",
825→        "properties": {
826→            "query": {
827→                "anyOf": [
828→                    {
829→                        "anyOf": [
830→                            {
831→                                "not": {
832→                                    "const": ""
