 172→/// Canonicalized JSON Schema document.
 173→///
 174→/// This wrapper intentionally keeps the canonical representation opaque so
 175→/// callers have to construct it through `canonicalize_schema`.
 176→#[derive(Debug, Clone, PartialEq, Eq)]
 177→pub(crate) struct CanonicalSchema {
 178→    value: Value,
 179→}
 180→
 181→impl CanonicalSchema {
 182→    pub(crate) fn as_value(&self) -> &Value {
 183→        &self.value
 184→    }
 185→
 186→    #[cfg(test)]
 187→    pub(crate) fn into_value(self) -> Value {
 188→        self.value
 189→    }
 190→}
 191→
 192→impl AsRef<Value> for CanonicalSchema {
 193→    fn as_ref(&self) -> &Value {
 194→        self.as_value()
 195→    }
