 198→/// Canonicalize a JSON Schema document by surfacing implicit constraints,
 199→/// lowering syntax sugar into explicit forms, preserving declaration metadata
 200→/// used by downstream codegen, and applying a deterministic key/value ordering.
 201→pub(crate) fn canonicalize_schema(schema: &Value) -> Result<CanonicalSchema> {
 202→    validate_schema_dialects(schema)?;
 203→
 204→    let local_ref_targets = collect_local_schema_refs(schema);
 205→    let options = CanonicalizationOptions {
 206→        local_ref_targets: &local_ref_targets,
 207→    };
 208→
 209→    Ok(CanonicalSchema {
 210→        value: canonicalize_schema_value(schema, "#", options)?,
 211→    })
 212→}
