 214→pub(crate) fn validate_schema_dialects(schema: &Value) -> Result<()> {
 215→    let local_ref_targets = collect_local_schema_refs(schema);
 216→    validate_schema_dialects_at_pointer(schema, "#", &local_ref_targets)
 217→}
 218→
 219→fn validate_schema_dialects_at_pointer(
 220→    schema: &Value,
 221→    pointer: &str,
 222→    local_ref_targets: &BTreeSet<String>,
 223→) -> Result<()> {
 224→    match schema {
 225→        Value::Object(object) => {
 226→            if let Some(schema_uri) = object.get("$schema") {
 227→                canonicalize_schema_uri(schema_uri, &join_pointer(pointer, "$schema"))?;
 228→            }
 229→            for (key, value) in object {
 230→                if should_strip_keyword(key) {
 231→                    continue;
 232→                }
 233→
 234→                let child_pointer = join_pointer(pointer, key);
 235→                if is_known_keyword(key) {
 236→                    validate_known_keyword_dialects(key, value, &child_pointer, local_ref_targets)?;
 237→                } else if preserve_unknown_keyword_at_pointer(&child_pointer, local_ref_targets) {
 238→                    validate_unknown_keyword_dialects(value, &child_pointer, local_ref_targets)?;
 239→                }
 240→            }
 241→        }
 242→        Value::Array(_) | Value::Null | Value::Bool(_) | Value::Number(_) | Value::String(_) => {}
 243→    }
 244→
 245→    Ok(())
 246→}
 247→
 248→fn validate_known_keyword_dialects(
 249→    key: &str,
 250→    value: &Value,
 251→    pointer: &str,
 252→    local_ref_targets: &BTreeSet<String>,
 253→) -> Result<()> {
 254→    match key {
 255→        "$schema" => Ok(()),
 256→        "not"
 257→        | "if"
 258→        | "then"
 259→        | "else"
 260→        | "contains"
 261→        | "additionalProperties"
 262→        | "propertyNames"
 263→        | "unevaluatedItems"
 264→        | "unevaluatedProperties"
 265→        | "contentSchema"
 266→        | "items" => validate_schema_dialects_at_pointer(value, pointer, local_ref_targets),
 267→        "allOf" | "anyOf" | "oneOf" | "prefixItems" => {
 268→            if let Value::Array(items) = value {
 269→                for (index, item) in items.iter().enumerate() {
 270→                    validate_schema_dialects_at_pointer(
 271→                        item,
 272→                        &join_pointer(pointer, &index.to_string()),
 273→                        local_ref_targets,
 274→                    )?;
 275→                }
 276→            }
 277→            Ok(())
 278→        }
 279→        "properties" | "patternProperties" | "$defs" | "definitions" | "dependentSchemas" => {
 280→            if let Value::Object(entries) = value {
 281→                for (name, child) in entries {
 282→                    validate_schema_dialects_at_pointer(
 283→                        child,
 284→                        &join_pointer(pointer, name),
 285→                        local_ref_targets,
 286→                    )?;
 287→                }
 288→            }
 289→            Ok(())
 290→        }
 291→        _ => Ok(()),
 292→    }
 293→}
 294→
 295→fn validate_unknown_keyword_dialects(
 296→    value: &Value,
 297→    pointer: &str,
 298→    local_ref_targets: &BTreeSet<String>,
 299→) -> Result<()> {
 300→    match value {
 301→        Value::Object(_) | Value::Bool(_) => {
 302→            validate_schema_dialects_at_pointer(value, pointer, local_ref_targets)
 303→        }
 304→        Value::Array(items) => {
 305→            for (index, item) in items.iter().enumerate() {
 306→                validate_unknown_keyword_dialects(
 307→                    item,
 308→                    &join_pointer(pointer, &index.to_string()),
 309→                    local_ref_targets,
 310→                )?;
 311→            }
 312→            Ok(())
 313→        }
 314→        Value::Null | Value::Number(_) | Value::String(_) => Ok(()),
 315→    }
 316→}
 317→
 318→/// Return a recursively key-sorted clone of arbitrary JSON data.
 319→pub(crate) fn canonicalize_json(value: &Value) -> Value {
 320→    match value {
 321→        Value::Object(obj) => Value::Object(sorted_object(
 322→            obj.iter()
 323→                .map(|(key, value)| (key.clone(), canonicalize_json(value)))
 324→                .collect(),
 325→        )),
 326→        Value::Array(items) => Value::Array(items.iter().map(canonicalize_json).collect()),
 327→        _ => value.clone(),
 328→    }
 329→}
 330→
 331→fn canonicalize_schema_value(
 332→    schema: &Value,
 333→    pointer: &str,
 334→    options: CanonicalizationOptions<'_>,
 335→) -> Result<Value> {
 336→    match schema {
 337→        Value::Bool(_) => Ok(schema.clone()),
 338→        Value::Object(obj) => canonicalize_schema_object(obj, pointer, options),
 339→        _ => Err(CanonicalizeError::InvalidSchemaNodeType {
 340→            pointer: pointer.to_owned(),
 341→            actual_type: json_type_name(schema),
 342→        }),
 343→    }
 344→}
 345→
 346→fn canonicalize_schema_object(
 347→    obj: &Map<String, Value>,
 348→    pointer: &str,
 349→    options: CanonicalizationOptions<'_>,
 350→) -> Result<Value> {
 351→    let mut current = canonicalize_schema_members(obj, pointer, options)?;
 352→
 353→    for _ in 0..MAX_PASSES {
 354→        let next = rewrite_schema_object(&current, pointer, options)?;
 355→        if next == current {
 356→            return Ok(match next {
 357→                Value::Object(obj) if obj.is_empty() => Value::Bool(true),
 358→                other => other,
 359→            });
 360→        }
 361→        current = match next {
 362→            Value::Object(obj) => canonicalize_schema_members(&obj, pointer, options)?,
 363→            Value::Bool(_) => next,
 364→            _ => {
 365→                return Err(CanonicalizeError::InvalidRewriteOutput {
 366→                    pointer: pointer.to_owned(),
 367→                    actual_type: json_type_name(&next),
 368→                });
 369→            }
 370→        };
 371→    }
 372→
 373→    Err(CanonicalizeError::RewriteDidNotConverge {
 374→        pointer: pointer.to_owned(),
 375→        passes: MAX_PASSES,
 376→    })
 377→}
 378→
 379→fn canonicalize_schema_members(
 380→    obj: &Map<String, Value>,
 381→    pointer: &str,
 382→    options: CanonicalizationOptions<'_>,
 383→) -> Result<Value> {
 384→    let mut canonical = Map::new();
 385→    for (key, value) in obj {
 386→        if should_strip_keyword(key) {
 387→            continue;
 388→        }
 389→
 390→        if !is_known_keyword(key) {
 391→            let pointer = join_pointer(pointer, key);
 392→            if !preserve_unknown_keyword_at_pointer(&pointer, options.local_ref_targets) {
 393→                continue;
 394→            }
 395→
 396→            canonical.insert(
 397→                key.clone(),
 398→                canonicalize_unknown_keyword_value(value, &pointer, options)?,
 399→            );
 400→            continue;
 401→        }
 402→
 403→        let pointer = join_pointer(pointer, key);
 404→        let value = canonicalize_keyword_value(key, value, &pointer, options)?;
 405→        canonical.insert(key.clone(), value);
 406→    }
 407→
 408→    Ok(Value::Object(sorted_object(canonical)))
 409→}
 410→
 411→fn canonicalize_keyword_value(
 412→    key: &str,
 413→    value: &Value,
 414→    pointer: &str,
 415→    options: CanonicalizationOptions<'_>,
 416→) -> Result<Value> {
 417→    match key {
 418→        "not"
 419→        | "if"
 420→        | "then"
 421→        | "else"
 422→        | "contains"
 423→        | "additionalProperties"
 424→        | "propertyNames"
 425→        | "unevaluatedItems"
 426→        | "unevaluatedProperties"
 427→        | "contentSchema"
 428→        | "items" => canonicalize_schema_value(value, pointer, options),
 429→        "allOf" | "anyOf" | "oneOf" | "prefixItems" => {
 430→            let items = value
 431→                .as_array()
 432→                .ok_or_else(|| invalid_keyword_type(pointer, key, "an array", value))?;
 433→            items
 434→                .iter()
 435→                .enumerate()
 436→                .map(|(index, item)| {
 437→                    canonicalize_schema_value(
 438→                        item,
 439→                        &join_pointer(pointer, &index.to_string()),
 440→                        options,
 441→                    )
 442→                })
 443→                .collect::<Result<Vec<_>>>()
 444→                .map(Value::Array)
 445→        }
 446→        "properties" | "patternProperties" | "$defs" | "definitions" | "dependentSchemas" => {
 447→            let entries = value
 448→                .as_object()
 449→                .ok_or_else(|| invalid_keyword_type(pointer, key, "an object", value))?;
 450→            let mut canonical = Map::new();
 451→            for (name, child) in entries {
 452→                canonical.insert(
 453→                    name.clone(),
 454→                    canonicalize_schema_value(child, &join_pointer(pointer, name), options)?,
 455→                );
 456→            }
 457→            Ok(Value::Object(sorted_object(canonical)))
 458→        }
 459→        "required" => {
 460→            let items = value.as_array().ok_or_else(|| {
 461→                invalid_keyword_type(pointer, "required", "an array of strings", value)
 462→            })?;
 463→            let mut names = BTreeSet::new();
 464→            for (index, item) in items.iter().enumerate() {
 465→                let Some(name) = item.as_str() else {
 466→                    return Err(invalid_keyword_entry_type(
 467→                        pointer, "required", index, "a string", item,
 468→                    ));
 469→                };
 470→                names.insert(name.to_owned());
 471→            }
 472→            Ok(Value::Array(names.into_iter().map(Value::String).collect()))
 473→        }
 474→        "dependentRequired" => {
 475→            let entries = value.as_object().ok_or_else(|| {
 476→                invalid_keyword_type(pointer, "dependentRequired", "an object", value)
 477→            })?;
 478→            let mut canonical = Map::new();
 479→            for (name, deps) in entries {
 480→                let deps = deps.as_array().ok_or_else(|| {
 481→                    invalid_keyword_type(
 482→                        &join_pointer(pointer, name),
 483→                        "dependentRequired",
 484→                        "an array of strings",
 485→                        deps,
 486→                    )
 487→                })?;
 488→                let mut sorted_deps = BTreeSet::new();
 489→                let dep_pointer = join_pointer(pointer, name);
 490→                for (index, dep) in deps.iter().enumerate() {
 491→                    let Some(dep) = dep.as_str() else {
 492→                        return Err(invalid_keyword_entry_type(
 493→                            &dep_pointer,
 494→                            "dependentRequired",
 495→                            index,
 496→                            "a string",
 497→                            dep,
 498→                        ));
 499→                    };
 500→                    sorted_deps.insert(dep.to_owned());
 501→                }
 502→                canonical.insert(
 503→                    name.clone(),
 504→                    Value::Array(sorted_deps.into_iter().map(Value::String).collect()),
 505→                );
 506→            }
 507→            Ok(Value::Object(sorted_object(canonical)))
 508→        }
 509→        "enum" => {
 510→            let items = value
 511→                .as_array()
 512→                .ok_or_else(|| invalid_keyword_type(pointer, "enum", "an array", value))?;
 513→            Ok(Value::Array(sorted_unique_json(items)))
 514→        }
 515→        "type" => match value {
 516→            Value::String(_) => Ok(value.clone()),
 517→            Value::Array(items) => {
 518→                let mut unique = BTreeSet::new();
 519→                for (index, item) in items.iter().enumerate() {
 520→                    let Some(type_name) = item.as_str() else {
 521→                        return Err(invalid_keyword_entry_type(
 522→                            pointer, "type", index, "a string", item,
 523→                        ));
 524→                    };
 525→                    unique.insert(type_name.to_owned());
 526→                }
 527→                Ok(Value::Array(
 528→                    unique.into_iter().map(Value::String).collect(),
 529→                ))
 530→            }
 531→            _ => Err(invalid_keyword_type(
 532→                pointer,
 533→                "type",
 534→                "a string or an array of strings",
 535→                value,
 536→            )),
 537→        },
 538→        "minLength" | "maxLength" | "minItems" | "maxItems" | "minContains" | "maxContains"
 539→        | "minProperties" | "maxProperties" => {
 540→            canonicalize_unsigned_integer_keyword(key, value, pointer)
 541→        }
 542→        "minimum" | "maximum" | "exclusiveMinimum" | "exclusiveMaximum" | "multipleOf" => {
 543→            canonicalize_numeric_keyword(key, value, pointer)
 544→        }
 545→        "pattern" | "format" | "contentEncoding" | "contentMediaType" | "$id" | "$anchor"
 546→        | "$dynamicRef" | "$dynamicAnchor" | "$ref" => {
 547→            canonicalize_string_keyword(key, value, pointer)
 548→        }
 549→        "uniqueItems" => canonicalize_boolean_keyword("uniqueItems", value, pointer),
 550→        "$schema" => canonicalize_schema_uri(value, pointer),
 551→        "const" | "default" | JSONCOMPAT_METADATA_KEY => Ok(canonicalize_json(value)),
 552→        "examples" => {
 553→            let items = value
 554→                .as_array()
 555→                .ok_or_else(|| invalid_keyword_type(pointer, "examples", "an array", value))?;
 556→            Ok(Value::Array(items.iter().map(canonicalize_json).collect()))
 557→        }
 558→        _ => Ok(canonicalize_json(value)),
 559→    }
 560→}
 561→
 562→fn canonicalize_unknown_keyword_value(
 563→    value: &Value,
 564→    pointer: &str,
 565→    options: CanonicalizationOptions<'_>,
 566→) -> Result<Value> {
 567→    match value {
 568→        Value::Object(_) | Value::Bool(_) => canonicalize_schema_value(value, pointer, options),
 569→        Value::Array(items) => items
 570→            .iter()
 571→            .enumerate()
 572→            .map(|(index, item)| {
 573→                canonicalize_unknown_keyword_value(
 574→                    item,
 575→                    &join_pointer(pointer, &index.to_string()),
 576→                    options,
 577→                )
 578→            })
 579→            .collect::<Result<Vec<_>>>()
 580→            .map(Value::Array),
 581→        _ => Ok(canonicalize_json(value)),
 582→    }
 583→}
 584→
 585→fn rewrite_schema_object(
 586→    schema: &Value,
 587→    pointer: &str,
 588→    options: CanonicalizationOptions<'_>,
 589→) -> Result<Value> {
 590→    let Value::Object(source) = schema else {
 591→        return Ok(schema.clone());
 592→    };
 593→    let mut obj = source.clone();
 594→
 595→    normalize_schema_uri(&mut obj);
 596→    remove_not_false(&mut obj, pointer, options.local_ref_targets);
 597→    remove_empty_conditionals(&mut obj, pointer, options.local_ref_targets);
 598→    remove_without_dependencies(&mut obj, pointer, options.local_ref_targets);
 599→    dedupe_required(&mut obj, pointer)?;
 600→    dedupe_enum(&mut obj);
 601→    dedupe_schema_array(&mut obj, "allOf", pointer, options.local_ref_targets);
 602→    dedupe_schema_array(&mut obj, "anyOf", pointer, options.local_ref_targets);
 603→    simplify_allof(&mut obj, pointer, options.local_ref_targets);
 604→    if let Some(result) = simplify_anyof(&mut obj, pointer, options.local_ref_targets) {
 605→        return Ok(result);
 606→    }
 607→    if let Some(result) = simplify_oneof(&mut obj, pointer, options.local_ref_targets) {
 608→        return Ok(result);
 609→    }
 610→    fold_required_dependencies(&mut obj, pointer)?;
 611→    infer_required_properties(&mut obj, pointer)?;
 612→    if let Some(result) = normalize_numeric_bounds(&mut obj, pointer)? {
 613→        return Ok(result);
 614→    }
 615→    normalize_single_type_arrays(&mut obj, pointer)?;
 616→    normalize_type_specific_keywords(&mut obj, pointer, options.local_ref_targets);
 617→    lower_const_with_type(&mut obj);
 618→    lower_enum_with_type(&mut obj);
 619→    if let Some(result) = lower_equal_bounds_to_enum(&mut obj, pointer)? {
 620→        return Ok(result);
 621→    }
 622→    if let Some(result) = lower_const_to_enum(&mut obj) {
 623→        return Ok(result);
 624→    }
 625→    lower_boolean_and_null_types(&mut obj);
 626→    insert_implicit_type_union(&mut obj, pointer, options.local_ref_targets);
 627→    lower_type_array_to_any_of(&mut obj, pointer)?;
 628→    if let Some(result) = rewrite_unsatisfiable_object(&obj, pointer, options.local_ref_targets) {
 629→        return Ok(result);
 630→    }
 631→    fill_implicit_constraints(&mut obj);
 632→
 633→    let schema = Value::Object(sorted_object(obj));
 634→    if let Value::Object(obj) = &schema
 635→        && obj.is_empty()
 636→    {
 637→        return Ok(Value::Bool(true));
 638→    }
 639→
 640→    Ok(schema)
 641→}
 642→
 643→fn normalize_schema_uri(schema: &mut Map<String, Value>) {
 644→    let Some(Value::String(uri)) = schema.get_mut("$schema") else {
 645→        return;
 646→    };
 647→
 648→    if uri == JSON_SCHEMA_DRAFT_2020_12_WITH_FRAGMENT {
 649→        uri.pop();
 650→    }
 651→}
 652→
 653→fn canonicalize_schema_uri(value: &Value, pointer: &str) -> Result<Value> {
 654→    let Some(uri) = value.as_str() else {
 655→        return Err(invalid_keyword_type(
 656→            pointer,
 657→            "$schema",
 658→            "a URI string",
 659→            value,
 660→        ));
 661→    };
 662→
 663→    match uri {
 664→        JSON_SCHEMA_DRAFT_2020_12 | JSON_SCHEMA_DRAFT_2020_12_WITH_FRAGMENT => {
 665→            Ok(Value::String(JSON_SCHEMA_DRAFT_2020_12.to_owned()))
 666→        }
 667→        _ => Err(CanonicalizeError::UnsupportedSchemaDialect {
 668→            pointer: pointer.to_owned(),
 669→            expected_uri: JSON_SCHEMA_DRAFT_2020_12,
 670→            actual_uri: uri.to_owned(),
 671→        }),
 672→    }
 673→}
 674→
 675→fn canonicalize_string_keyword(key: &str, value: &Value, pointer: &str) -> Result<Value> {
 676→    value
 677→        .as_str()
 678→        .ok_or_else(|| invalid_keyword_type(pointer, key, "a string", value))?;
 679→    Ok(value.clone())
 680→}
 681→
 682→fn canonicalize_unsigned_integer_keyword(key: &str, value: &Value, pointer: &str) -> Result<Value> {
 683→    let Some(integer) =
 684→        semantic_integer_value_from_json(value).and_then(|integer| u64::try_from(integer).ok())
 685→    else {
 686→        return Err(invalid_keyword_type(
 687→            pointer,
 688→            key,
 689→            "a non-negative integer",
 690→            value,
 691→        ));
 692→    };
 693→    Ok(Value::Number(Number::from(integer)))
 694→}
 695→
 696→fn canonicalize_boolean_keyword(key: &str, value: &Value, pointer: &str) -> Result<Value> {
 697→    value
 698→        .as_bool()
 699→        .ok_or_else(|| invalid_keyword_type(pointer, key, "a boolean", value))?;
 700→    Ok(value.clone())
 701→}
 702→
 703→fn canonicalize_numeric_keyword(key: &str, value: &Value, pointer: &str) -> Result<Value> {
 704→    let Some(number) = value.as_f64() else {
 705→        return Err(invalid_keyword_type(pointer, key, "a finite number", value));
 706→    };
 707→    if !number.is_finite() {
 708→        return Err(CanonicalizeError::NonFiniteNumericKeyword {
 709→            pointer: pointer.to_owned(),
 710→            keyword: key.to_owned(),
 711→        });
 712→    }
 713→    if key == "multipleOf" && number <= 0.0 {
 714→        return Err(invalid_keyword_type(
 715→            pointer,
 716→            key,
 717→            "a positive number",
 718→            value,
 719→        ));
 720→    }
 721→
 722→    Ok(value.clone())
 723→}
 724→
 725→fn remove_not_false(
 726→    schema: &mut Map<String, Value>,
 727→    pointer: &str,
 728→    local_ref_targets: &BTreeSet<String>,
 729→) {
 730→    if schema.get("not") == Some(&Value::Bool(false))
 731→        && !preserve_unknown_keyword_at_pointer(&join_pointer(pointer, "not"), local_ref_targets)
 732→    {
 733→        schema.remove("not");
 734→    }
 735→}
 736→
 737→fn remove_empty_conditionals(
 738→    schema: &mut Map<String, Value>,
 739→    pointer: &str,
 740→    local_ref_targets: &BTreeSet<String>,
 741→) {
 742→    if matches!(schema.get("then"), Some(Value::Bool(true))) {
 743→        schema.remove("then");
 744→    }
 745→    if matches!(schema.get("else"), Some(Value::Bool(true))) {
 746→        schema.remove("else");
 747→    }
 748→    if let Some(if_schema) = schema.get("if")
 749→        && !schema.contains_key("then")
 750→        && !schema.contains_key("else")
 751→        && !schema_contains_resource_identifier(if_schema)
 752→        && !preserve_unknown_keyword_at_pointer(&join_pointer(pointer, "if"), local_ref_targets)
 753→    {
 754→        schema.remove("if");
 755→    }
 756→}
 757→
 758→fn remove_without_dependencies(
 759→    schema: &mut Map<String, Value>,
 760→    pointer: &str,
 761→    local_ref_targets: &BTreeSet<String>,
 762→) {
 763→    if !schema.contains_key("if") {
 764→        if schema.get("then").is_some_and(|then_schema| {
 765→            !schema_contains_resource_identifier(then_schema)
 766→                && !preserve_unknown_keyword_at_pointer(
 767→                    &join_pointer(pointer, "then"),
 768→                    local_ref_targets,
 769→                )
 770→        }) {
 771→            schema.remove("then");
 772→        }
 773→        if schema.get("else").is_some_and(|else_schema| {
 774→            !schema_contains_resource_identifier(else_schema)
 775→                && !preserve_unknown_keyword_at_pointer(
 776→                    &join_pointer(pointer, "else"),
 777→                    local_ref_targets,
 778→                )
 779→        }) {
 780→            schema.remove("else");
 781→        }
 782→    }
 783→    if !schema.contains_key("contains") {
 784→        schema.remove("minContains");
 785→        schema.remove("maxContains");
 786→    }
 787→    if !schema.contains_key("contentEncoding") {
 788→        schema.remove("contentMediaType");
 789→    }
 790→    if !schema.contains_key("contentMediaType") {
 791→        schema.remove("contentSchema");
 792→    }
 793→    if !matches!(schema.get("items"), Some(Value::Array(_))) {
 794→        schema.remove("additionalItems");
 795→    }
 796→}
