 798→fn dedupe_required(schema: &mut Map<String, Value>, pointer: &str) -> Result<()> {
 799→    let Some(Value::Array(required)) = schema.get("required") else {
 800→        return Ok(());
 801→    };
 802→    let mut names = BTreeSet::new();
 803→    let required_pointer = join_pointer(pointer, "required");
 804→    for (index, name) in required.iter().enumerate() {
 805→        let Some(name) = name.as_str() else {
 806→            return Err(invalid_keyword_entry_type(
 807→                &required_pointer,
 808→                "required",
 809→                index,
 810→                "a string",
 811→                name,
 812→            ));
 813→        };
 814→        names.insert(name.to_owned());
 815→    }
 816→    schema.insert(
 817→        "required".to_owned(),
 818→        Value::Array(names.into_iter().map(Value::String).collect()),
 819→    );
 820→    Ok(())
 821→}
 822→
 823→fn dedupe_enum(schema: &mut Map<String, Value>) {
 824→    let Some(Value::Array(values)) = schema.get("enum") else {
 825→        return;
 826→    };
 827→    schema.insert("enum".to_owned(), Value::Array(sorted_unique_json(values)));
 828→}
 829→
 830→fn dedupe_schema_array(
 831→    schema: &mut Map<String, Value>,
 832→    keyword: &str,
 833→    pointer: &str,
 834→    local_ref_targets: &BTreeSet<String>,
 835→) {
 836→    let Some(Value::Array(values)) = schema.get(keyword) else {
 837→        return;
 838→    };
 839→
 840→    if preserve_unknown_keyword_at_pointer(&join_pointer(pointer, keyword), local_ref_targets) {
 841→        return;
 842→    }
 843→
 844→    let mut seen = BTreeSet::new();
 845→    let mut unique = Vec::new();
 846→    for value in values {
 847→        let key = serde_json::to_string(&canonicalize_json(value))
 848→            .expect("serializing canonical JSON value cannot fail");
 849→        if seen.insert(key) {
 850→            unique.push(value.clone());
 851→        }
 852→    }
 853→    schema.insert(keyword.to_owned(), Value::Array(unique));
 854→}
 855→
 856→fn simplify_allof(
 857→    schema: &mut Map<String, Value>,
 858→    pointer: &str,
 859→    local_ref_targets: &BTreeSet<String>,
 860→) {
 861→    let Some(Value::Array(branches)) = schema.get_mut("allOf") else {
 862→        return;
 863→    };
 864→
 865→    if preserve_unknown_keyword_at_pointer(&join_pointer(pointer, "allOf"), local_ref_targets) {
 866→        return;
 867→    }
 868→
 869→    if branches.iter().any(|branch| branch == &Value::Bool(false)) {
 870→        let preserved = if preserve_unknown_keyword_at_pointer(pointer, local_ref_targets) {
 871→            preserved_meta(schema)
 872→        } else {
 873→            preserved_terminal_meta(schema)
 874→        };
 875→        schema.clear();
 876→        schema.extend(preserved);
 877→        schema.insert("not".to_owned(), Value::Bool(true));
 878→        return;
 879→    }
 880→
 881→    branches.retain(|branch| branch != &Value::Bool(true));
 882→    if branches.is_empty() {
 883→        schema.remove("allOf");
 884→    }
 885→}
 886→
 887→fn simplify_anyof(
 888→    schema: &mut Map<String, Value>,
 889→    pointer: &str,
 890→    local_ref_targets: &BTreeSet<String>,
 891→) -> Option<Value> {
 892→    let Some(Value::Array(branches)) = schema.get_mut("anyOf") else {
 893→        return None;
 894→    };
 895→
 896→    if preserve_unknown_keyword_at_pointer(&join_pointer(pointer, "anyOf"), local_ref_targets) {
 897→        return None;
 898→    }
 899→
 900→    if branches.iter().any(|branch| branch == &Value::Bool(true)) {
 901→        schema.remove("anyOf");
 902→        return None;
 903→    }
 904→
 905→    branches.retain(|branch| branch != &Value::Bool(false));
 906→    if branches.is_empty() || (branches.len() == 1 && branches[0] == Value::Bool(false)) {
 907→        let mut obj = if preserve_unknown_keyword_at_pointer(pointer, local_ref_targets) {
 908→            preserved_meta(schema)
 909→        } else {
 910→            preserved_terminal_meta(schema)
 911→        };
 912→        obj.insert("not".to_owned(), Value::Bool(true));
 913→        return Some(Value::Object(sorted_object(obj)));
 914→    }
 915→    if branches.is_empty() {
 916→        schema.remove("anyOf");
 917→    }
 918→    None
 919→}
 920→
 921→fn simplify_oneof(
 922→    schema: &mut Map<String, Value>,
 923→    pointer: &str,
 924→    local_ref_targets: &BTreeSet<String>,
 925→) -> Option<Value> {
 926→    let Some(Value::Array(branches)) = schema.get("oneOf") else {
 927→        return None;
 928→    };
 929→
 930→    if preserve_unknown_keyword_at_pointer(&join_pointer(pointer, "oneOf"), local_ref_targets) {
 931→        return None;
 932→    }
 933→
 934→    if branches.len() == 1 && branches[0] == Value::Bool(false) {
 935→        let mut obj = if preserve_unknown_keyword_at_pointer(pointer, local_ref_targets) {
 936→            preserved_meta(schema)
 937→        } else {
 938→            preserved_terminal_meta(schema)
 939→        };
 940→        obj.insert("not".to_owned(), Value::Bool(true));
 941→        return Some(Value::Object(sorted_object(obj)));
 942→    }
 943→
 944→    if can_rewrite_oneof_to_anyof(branches) {
 945→        let branches = branches.clone();
 946→        schema.remove("oneOf");
 947→        schema.insert("anyOf".to_owned(), Value::Array(branches));
 948→    }
 949→    None
 950→}
 951→
 952→#[must_use]
 953→fn can_rewrite_oneof_to_anyof(branches: &[Value]) -> bool {
 954→    let mut seen_types = PrimitiveTypeSet::empty();
 955→    if branches.len() < 2 {
 956→        return false;
 957→    }
 958→
 959→    for branch in branches {
 960→        let Some(types) = branch_type_set(branch) else {
 961→            return false;
 962→        };
 963→        if types.is_empty() {
 964→            return false;
 965→        }
 966→        if seen_types.intersects(types) {
 967→            return false;
 968→        }
 969→        seen_types |= types;
 970→    }
 971→
 972→    true
 973→}
 974→
 975→#[must_use]
 976→fn branch_type_set(branch: &Value) -> Option<PrimitiveTypeSet> {
 977→    match branch {
 978→        Value::Bool(true) => None,
 979→        Value::Bool(false) => Some(PrimitiveTypeSet::empty()),
 980→        Value::Object(obj) => {
 981→            if let Some(Value::String(type_name)) = obj.get("type") {
 982→                return primitive_type_set(type_name.as_str());
 983→            }
 984→            if let Some(Value::Array(values)) = obj.get("enum") {
 985→                let mut types = PrimitiveTypeSet::empty();
 986→                for value in values {
 987→                    types |= value_type_name(value)?;
 988→                }
 989→                return Some(types);
 990→            }
 991→            None
 992→        }
 993→        _ => None,
 994→    }
 995→}
 996→
 997→#[must_use]
 998→fn primitive_type_set(type_name: &str) -> Option<PrimitiveTypeSet> {
 999→    match type_name {
1000→        "null" => Some(PrimitiveType::Null.into()),
1001→        "boolean" => Some(PrimitiveType::Boolean.into()),
1002→        "object" => Some(PrimitiveType::Object.into()),
1003→        "array" => Some(PrimitiveType::Array.into()),
1004→        "string" => Some(PrimitiveType::String.into()),
1005→        "number" => Some(
1006→            PrimitiveTypeSet::from(PrimitiveType::Number)
1007→                | PrimitiveTypeSet::from(PrimitiveType::Integer),
1008→        ),
1009→        "integer" => Some(PrimitiveType::Integer.into()),
1010→        _ => None,
1011→    }
1012→}
1013→
1014→#[must_use]
1015→fn value_type_name(value: &Value) -> Option<PrimitiveType> {
1016→    match value {
1017→        Value::Null => Some(PrimitiveType::Null),
1018→        Value::Bool(_) => Some(PrimitiveType::Boolean),
1019→        Value::Object(_) => Some(PrimitiveType::Object),
1020→        Value::Array(_) => Some(PrimitiveType::Array),
1021→        Value::String(_) => Some(PrimitiveType::String),
1022→        Value::Number(number) if number.is_i64() || number.is_u64() => Some(PrimitiveType::Integer),
1023→        // This is a bit unfortunate because it relies on f64 semantics, but JSON
1024→        // Schema's "integer" type intentionally accepts values like 1.0.
1025→        Value::Number(number) if number.as_f64().is_some_and(|value| value.fract() == 0.0) => {
1026→            Some(PrimitiveType::Integer)
1027→        }
1028→        Value::Number(_) => Some(PrimitiveType::Number),
1029→    }
1030→}
1031→
1032→pub(crate) fn json_type_name(value: &Value) -> &'static str {
1033→    match value {
1034→        Value::Null => "null",
1035→        Value::Bool(_) => "boolean",
1036→        Value::Object(_) => "object",
1037→        Value::Array(_) => "array",
1038→        Value::String(_) => "string",
1039→        Value::Number(_) => "number",
1040→    }
1041→}
