1077→fn fold_required_dependencies(schema: &mut Map<String, Value>, pointer: &str) -> Result<()> {
1078→    let Some(Value::Object(dependent_required)) = schema.get("dependentRequired") else {
1079→        return Ok(());
1080→    };
1081→    let Some(Value::Array(required_values)) = schema.get("required") else {
1082→        return Ok(());
1083→    };
1084→
1085→    let required_pointer = join_pointer(pointer, "required");
1086→    let mut required = required_values
1087→        .iter()
1088→        .enumerate()
1089→        .map(|(index, value)| {
1090→            value.as_str().map(str::to_owned).ok_or_else(|| {
1091→                invalid_keyword_entry_type(&required_pointer, "required", index, "a string", value)
1092→            })
1093→        })
1094→        .collect::<Result<BTreeSet<_>>>()?;
1095→
1096→    let mut remaining = dependent_required.clone();
1097→    loop {
1098→        let mut changed = false;
1099→        let triggers = required.iter().cloned().collect::<Vec<_>>();
1100→        for trigger in triggers {
1101→            let Some(Value::Array(deps)) = remaining.remove(&trigger) else {
1102→                continue;
1103→            };
1104→            let trigger_pointer = join_pointer(
1105→                &join_pointer(pointer, "dependentRequired"),
1106→                &escape_pointer_token(&trigger),
1107→            );
1108→            for (index, dep) in deps.iter().enumerate() {
1109→                let dep = dep.as_str().ok_or_else(|| {
1110→                    invalid_keyword_entry_type(
1111→                        &trigger_pointer,
1112→                        "dependentRequired",
1113→                        index,
1114→                        "a string",
1115→                        dep,
1116→                    )
1117→                })?;
1118→                changed |= required.insert(dep.to_owned());
1119→            }
1120→        }
1121→        if !changed {
1122→            break;
1123→        }
1124→    }
1125→
1126→    schema.insert(
1127→        "required".to_owned(),
1128→        Value::Array(required.into_iter().map(Value::String).collect()),
1129→    );
1130→    schema.insert(
1131→        "dependentRequired".to_owned(),
1132→        Value::Object(sorted_object(remaining)),
1133→    );
1134→    Ok(())
1135→}
