1137→fn infer_required_properties(schema: &mut Map<String, Value>, pointer: &str) -> Result<()> {
1138→    if schema.contains_key("additionalProperties") {
1139→        return Ok(());
1140→    }
1141→
1142→    let Some(Value::Array(required)) = schema.get("required") else {
1143→        return Ok(());
1144→    };
1145→
1146→    let mut properties = schema
1147→        .get("properties")
1148→        .and_then(Value::as_object)
1149→        .cloned()
1150→        .unwrap_or_default();
1151→
1152→    let required_pointer = join_pointer(pointer, "required");
1153→    for (index, name) in required.iter().enumerate() {
1154→        let Some(name) = name.as_str() else {
1155→            return Err(invalid_keyword_entry_type(
1156→                &required_pointer,
1157→                "required",
1158→                index,
1159→                "a string",
1160→                name,
1161→            ));
1162→        };
1163→        properties
1164→            .entry(name.to_owned())
1165→            .or_insert(Value::Bool(true));
1166→    }
1167→
1168→    if !properties.is_empty() {
1169→        schema.insert(
1170→            "properties".to_owned(),
1171→            Value::Object(sorted_object(properties)),
1172→        );
1173→    }
1174→    Ok(())
1175→}
