1177→fn normalize_numeric_bounds(
1178→    schema: &mut Map<String, Value>,
1179→    pointer: &str,
1180→) -> Result<Option<Value>> {
1181→    if let (Some(maximum), Some(exclusive_maximum)) =
1182→        (schema.get("maximum"), schema.get("exclusiveMaximum"))
1183→        && let (Some(maximum), Some(exclusive_maximum)) =
1184→            (maximum.as_f64(), exclusive_maximum.as_f64())
1185→    {
1186→        if maximum < exclusive_maximum {
1187→            schema.remove("exclusiveMaximum");
1188→        } else {
1189→            schema.remove("maximum");
1190→        }
1191→    }
1192→
1193→    if let (Some(minimum), Some(exclusive_minimum)) =
1194→        (schema.get("minimum"), schema.get("exclusiveMinimum"))
1195→        && let (Some(minimum), Some(exclusive_minimum)) =
1196→            (minimum.as_f64(), exclusive_minimum.as_f64())
1197→    {
1198→        if exclusive_minimum < minimum {
1199→            schema.remove("exclusiveMinimum");
1200→        } else {
1201→            schema.remove("minimum");
1202→        }
1203→    }
1204→
1205→    if schema.get("type") == Some(&Value::String("integer".to_owned())) {
1206→        if let Some(bound) = schema.get("maximum").cloned()
1207→            && let Some(bound) = integer_floor(&bound, &join_pointer(pointer, "maximum"))?
1208→        {
1209→            schema.insert("maximum".to_owned(), bound);
1210→        }
1211→        if let Some(bound) = schema.get("minimum").cloned()
1212→            && let Some(bound) = integer_ceil(&bound, &join_pointer(pointer, "minimum"))?
1213→        {
1214→            schema.insert("minimum".to_owned(), bound);
1215→        }
1216→        if !schema.contains_key("maximum")
1217→            && let Some(bound) = schema.get("exclusiveMaximum").cloned()
1218→            && let Some(bound) =
1219→                integer_exclusive_maximum(&bound, &join_pointer(pointer, "exclusiveMaximum"))?
1220→        {
1221→            schema.remove("exclusiveMaximum");
1222→            match bound {
1223→                NormalizedIntegerBound::Inclusive(bound) => {
1224→                    schema.insert("maximum".to_owned(), bound);
1225→                }
1226→                NormalizedIntegerBound::Unsatisfiable => {
1227→                    return Ok(Some(Value::Object(unsatisfiable_object(schema))));
1228→                }
1229→            }
1230→        }
1231→        if !schema.contains_key("minimum")
1232→            && let Some(bound) = schema.get("exclusiveMinimum").cloned()
1233→            && let Some(bound) =
1234→                integer_exclusive_minimum(&bound, &join_pointer(pointer, "exclusiveMinimum"))?
1235→        {
1236→            schema.remove("exclusiveMinimum");
1237→            match bound {
1238→                NormalizedIntegerBound::Inclusive(bound) => {
1239→                    schema.insert("minimum".to_owned(), bound);
1240→                }
1241→                NormalizedIntegerBound::Unsatisfiable => {
1242→                    return Ok(Some(Value::Object(unsatisfiable_object(schema))));
1243→                }
1244→            }
1245→        }
1246→    }
1247→
1248→    Ok(None)
1249→}
1250→
1251→fn integer_floor(value: &Value, pointer: &str) -> Result<Option<Value>> {
1252→    let Some(number) = value.as_number() else {
1253→        return Ok(None);
1254→    };
1255→    if let Some(value) = number.as_i64() {
1256→        return Ok(Some(Value::Number(Number::from(value))));
1257→    }
1258→    if let Some(value) = number.as_u64() {
1259→        return Ok(Some(Value::Number(Number::from(checked_i64_from_u64(
1260→            value, pointer,
1261→        )?))));
1262→    }
1263→    let Some(value) = number.as_f64() else {
1264→        return Err(CanonicalizeError::NonFiniteNumericKeyword {
1265→            pointer: pointer.to_owned(),
1266→            keyword: last_pointer_token(pointer),
1267→        });
1268→    };
1269→    Ok(Some(number_from_f64(value.floor(), pointer)?))
1270→}
1271→
1272→fn integer_ceil(value: &Value, pointer: &str) -> Result<Option<Value>> {
1273→    let Some(number) = value.as_number() else {
1274→        return Ok(None);
1275→    };
1276→    if let Some(value) = number.as_i64() {
1277→        return Ok(Some(Value::Number(Number::from(value))));
1278→    }
1279→    if let Some(value) = number.as_u64() {
1280→        return Ok(Some(Value::Number(Number::from(checked_i64_from_u64(
1281→            value, pointer,
1282→        )?))));
1283→    }
1284→    let Some(value) = number.as_f64() else {
1285→        return Err(CanonicalizeError::NonFiniteNumericKeyword {
1286→            pointer: pointer.to_owned(),
1287→            keyword: last_pointer_token(pointer),
1288→        });
1289→    };
1290→    Ok(Some(number_from_f64(value.ceil(), pointer)?))
1291→}
1292→
1293→fn integer_exclusive_maximum(
1294→    value: &Value,
1295→    pointer: &str,
1296→) -> Result<Option<NormalizedIntegerBound>> {
1297→    let Some(number) = value.as_number() else {
1298→        return Ok(None);
1299→    };
1300→    if let Some(value) = number.as_i64() {
1301→        return Ok(Some(
1302→            value
1303→                .checked_sub(1)
1304→                .map(|value| NormalizedIntegerBound::Inclusive(Value::Number(Number::from(value))))
1305→                .unwrap_or(NormalizedIntegerBound::Unsatisfiable),
1306→        ));
1307→    }
1308→    if let Some(value) = number.as_u64() {
1309→        return if value == 0 {
1310→            Ok(Some(NormalizedIntegerBound::Inclusive(Value::Number(
1311→                Number::from(-1_i64),
1312→            ))))
1313→        } else {
1314→            let maximum = (value - 1).min(i64::MAX as u64);
1315→            Ok(Some(NormalizedIntegerBound::Inclusive(Value::Number(
1316→                Number::from(maximum),
1317→            ))))
1318→        };
1319→    }
1320→    let Some(value) = number.as_f64() else {
1321→        return Err(CanonicalizeError::NonFiniteNumericKeyword {
1322→            pointer: pointer.to_owned(),
1323→            keyword: last_pointer_token(pointer),
1324→        });
1325→    };
1326→    let mut normalized = value.floor();
1327→    if value.fract() == 0.0 {
1328→        normalized -= 1.0;
1329→    }
1330→    if normalized < i64::MIN as f64 {
1331→        return Ok(Some(NormalizedIntegerBound::Unsatisfiable));
1332→    }
1333→    if normalized > i64::MAX as f64 {
1334→        return Ok(Some(NormalizedIntegerBound::Inclusive(Value::Number(
1335→            Number::from(i64::MAX),
1336→        ))));
1337→    }
1338→    Ok(Some(NormalizedIntegerBound::Inclusive(number_from_f64(
1339→        normalized, pointer,
1340→    )?)))
1341→}
1342→
1343→fn integer_exclusive_minimum(
1344→    value: &Value,
1345→    pointer: &str,
1346→) -> Result<Option<NormalizedIntegerBound>> {
1347→    let Some(number) = value.as_number() else {
1348→        return Ok(None);
1349→    };
1350→    if let Some(value) = number.as_i64() {
1351→        return Ok(Some(
1352→            value
1353→                .checked_add(1)
1354→                .map(|value| NormalizedIntegerBound::Inclusive(Value::Number(Number::from(value))))
1355→                .unwrap_or(NormalizedIntegerBound::Unsatisfiable),
1356→        ));
1357→    }
1358→    if let Some(value) = number.as_u64() {
1359→        if value >= i64::MAX as u64 {
1360→            return Ok(Some(NormalizedIntegerBound::Unsatisfiable));
1361→        }
1362→        return Ok(Some(NormalizedIntegerBound::Inclusive(Value::Number(
1363→            Number::from(value + 1),
1364→        ))));
1365→    }
1366→    let Some(value) = number.as_f64() else {
1367→        return Err(CanonicalizeError::NonFiniteNumericKeyword {
1368→            pointer: pointer.to_owned(),
1369→            keyword: last_pointer_token(pointer),
1370→        });
1371→    };
1372→    let mut normalized = value.ceil();
1373→    if value.fract() == 0.0 {
1374→        normalized += 1.0;
1375→    }
1376→    if normalized > i64::MAX as f64 {
1377→        return Ok(Some(NormalizedIntegerBound::Unsatisfiable));
1378→    }
1379→    if normalized < i64::MIN as f64 {
1380→        return Ok(Some(NormalizedIntegerBound::Inclusive(Value::Number(
1381→            Number::from(i64::MIN),
1382→        ))));
1383→    }
1384→    Ok(Some(NormalizedIntegerBound::Inclusive(number_from_f64(
1385→        normalized, pointer,
1386→    )?)))
1387→}
1388→
1389→fn number_from_f64(value: f64, pointer: &str) -> Result<Value> {
1390→    if value.fract() == 0.0 && value >= i64::MIN as f64 && value <= i64::MAX as f64 {
1391→        return Ok(Value::Number(Number::from(value as i64)));
1392→    }
1393→
1394→    let Some(number) = Number::from_f64(value) else {
1395→        return Err(CanonicalizeError::NonFiniteNumericKeyword {
1396→            pointer: pointer.to_owned(),
1397→            keyword: last_pointer_token(pointer),
1398→        });
1399→    };
1400→    Ok(Value::Number(number))
1401→}
