1423→fn normalize_type_specific_keywords(
1424→    schema: &mut Map<String, Value>,
1425→    pointer: &str,
1426→    local_ref_targets: &BTreeSet<String>,
1427→) {
1428→    let Some(type_name) = schema.get("type").and_then(Value::as_str) else {
1429→        return;
1430→    };
1431→
1432→    let allowed = match type_name {
1433→        "string" => Some(
1434→            [
1435→                "type",
1436→                "enum",
1437→                "const",
1438→                "minLength",
1439→                "maxLength",
1440→                "pattern",
1441→                "format",
1442→            ]
1443→            .as_slice(),
1444→        ),
1445→        "number" | "integer" => Some(
1446→            [
1447→                "type",
1448→                "enum",
1449→                "const",
1450→                "minimum",
1451→                "maximum",
1452→                "exclusiveMinimum",
1453→                "exclusiveMaximum",
1454→                "multipleOf",
1455→            ]
1456→            .as_slice(),
1457→        ),
1458→        "object" => Some(
1459→            [
1460→                "type",
1461→                "enum",
1462→                "const",
1463→                "properties",
1464→                "required",
1465→                "additionalProperties",
1466→                "patternProperties",
1467→                "propertyNames",
1468→                "minProperties",
1469→                "maxProperties",
1470→                "dependentRequired",
1471→                "dependentSchemas",
1472→                "unevaluatedProperties",
1473→            ]
1474→            .as_slice(),
1475→        ),
1476→        "array" => Some(
1477→            [
1478→                "type",
1479→                "enum",
1480→                "const",
1481→                "items",
1482→                "prefixItems",
1483→                "contains",
1484→                "minItems",
1485→                "maxItems",
1486→                "minContains",
1487→                "maxContains",
1488→                "uniqueItems",
1489→                "unevaluatedItems",
1490→            ]
1491→            .as_slice(),
1492→        ),
1493→        "boolean" | "null" => Some(["type", "enum", "const"].as_slice()),
1494→        _ => None,
1495→    };
1496→    let Some(allowed) = allowed else {
1497→        return;
1498→    };
1499→
1500→    schema.retain(|key, _| {
1501→        is_schema_metadata_key(key)
1502→            || allowed.contains(&key.as_str())
1503→            || preserve_unknown_keyword_at_pointer(&join_pointer(pointer, key), local_ref_targets)
1504→            || matches!(
1505→                key.as_str(),
1506→                "allOf"
1507→                    | "anyOf"
1508→                    | "oneOf"
1509→                    | "not"
1510→                    | "if"
1511→                    | "then"
1512→                    | "else"
1513→                    | "$ref"
1514→                    | "$dynamicRef"
1515→            )
1516→    });
1517→}
