1546→fn lower_equal_bounds_to_enum(
1547→    schema: &mut Map<String, Value>,
1548→    pointer: &str,
1549→) -> Result<Option<Value>> {
1550→    let Some(Value::String(type_name)) = schema.get("type") else {
1551→        return Ok(None);
1552→    };
1553→    if type_name != "integer" && type_name != "number" {
1554→        return Ok(None);
1555→    }
1556→    let (Some(minimum), Some(maximum)) = (schema.get("minimum"), schema.get("maximum")) else {
1557→        return Ok(None);
1558→    };
1559→    if minimum != maximum {
1560→        return Ok(None);
1561→    }
1562→    if let Some(multiple_of) = schema.get("multipleOf")
1563→        && !value_is_multiple_of(
1564→            minimum,
1565→            multiple_of,
1566→            type_name,
1567→            &join_pointer(pointer, "minimum"),
1568→            &join_pointer(pointer, "multipleOf"),
1569→        )?
1570→    {
1571→        return Ok(Some(Value::Object(unsatisfiable_object(schema))));
1572→    }
1573→    schema.insert(
1574→        "enum".to_owned(),
1575→        Value::Array(vec![canonicalize_json(minimum)]),
1576→    );
1577→    schema.remove("type");
1578→    schema.remove("minimum");
1579→    schema.remove("maximum");
1580→    schema.remove("multipleOf");
1581→    Ok(None)
1582→}
