1584→fn lower_const_to_enum(schema: &mut Map<String, Value>) -> Option<Value> {
1585→    let value = schema.remove("const")?;
1586→    let value = canonicalize_json(&value);
1587→
1588→    if let Some(Value::Array(values)) = schema.get("enum") {
1589→        if !values
1590→            .iter()
1591→            .any(|enum_value| json_values_equal(enum_value, &value))
1592→        {
1593→            return Some(Value::Object(unsatisfiable_object(schema)));
1594→        }
1595→        schema.insert("enum".to_owned(), Value::Array(vec![value]));
1596→        return None;
1597→    }
1598→
1599→    schema.insert("enum".to_owned(), Value::Array(vec![value]));
1600→    None
1601→}
