1623→fn insert_implicit_type_union(
1624→    schema: &mut Map<String, Value>,
1625→    pointer: &str,
1626→    local_ref_targets: &BTreeSet<String>,
1627→) {
1628→    if schema.is_empty()
1629→        || pointer_is_strict_ancestor_of_local_ref_target(pointer, local_ref_targets)
1630→    {
1631→        return;
1632→    }
1633→    if schema.contains_key("type")
1634→        || schema.contains_key("enum")
1635→        || schema.contains_key("const")
1636→        || schema.contains_key("$ref")
1637→        || schema.contains_key("$dynamicRef")
1638→        || schema.contains_key("allOf")
1639→        || schema.contains_key("anyOf")
1640→        || schema.contains_key("oneOf")
1641→        || schema.contains_key("not")
1642→        || schema.contains_key("if")
1643→        || schema.contains_key("then")
1644→        || schema.contains_key("else")
1645→        || contains_local_schema_refs(schema)
1646→    {
1647→        return;
1648→    }
1649→
1650→    schema.insert(
1651→        "type".to_owned(),
1652→        Value::Array(vec![
1653→            Value::String("null".to_owned()),
1654→            Value::String("boolean".to_owned()),
1655→            Value::String("object".to_owned()),
1656→            Value::String("array".to_owned()),
1657→            Value::String("string".to_owned()),
1658→            Value::String("number".to_owned()),
1659→        ]),
1660→    );
1661→}
