1663→fn pointer_is_strict_ancestor_of_local_ref_target(
1664→    pointer: &str,
1665→    local_ref_targets: &BTreeSet<String>,
1666→) -> bool {
1667→    let prefix = format!("{pointer}/");
1668→    local_ref_targets
1669→        .iter()
1670→        .any(|reference| reference.starts_with(&prefix))
1671→}
