1673→fn lower_type_array_to_any_of(schema: &mut Map<String, Value>, pointer: &str) -> Result<()> {
1674→    let Some(Value::Array(types)) = schema.get("type").cloned() else {
1675→        return Ok(());
1676→    };
1677→    if types.len() <= 1 {
1678→        return Ok(());
1679→    }
1680→    if contains_local_schema_refs(schema) {
1681→        return Ok(());
1682→    }
1683→
1684→    let mut preserved = preserved_meta(schema);
1685→    let mut branch_context = Map::new();
1686→    for (key, value) in schema.iter() {
1687→        if key == "type" || key == "anyOf" || is_schema_metadata_key(key) {
1688→            continue;
1689→        }
1690→        branch_context.insert(key.clone(), value.clone());
1691→    }
1692→
1693→    let mut branches = Vec::new();
1694→    let type_pointer = join_pointer(pointer, "type");
1695→    for (index, type_name) in types.iter().enumerate() {
1696→        let Some(type_name) = type_name.as_str() else {
1697→            return Err(invalid_keyword_entry_type(
1698→                &type_pointer,
1699→                "type",
1700→                index,
1701→                "a string",
1702→                type_name,
1703→            ));
1704→        };
1705→        let mut branch = branch_context.clone();
1706→        branch.insert("type".to_owned(), Value::String(type_name.to_owned()));
1707→        branches.push(Value::Object(sorted_object(branch)));
1708→    }
1709→
1710→    if let Some(existing_any_of) = schema.get("anyOf").cloned() {
1711→        let mut first = branch_context;
1712→        first.insert("anyOf".to_owned(), existing_any_of);
1713→        let mut second = Map::new();
1714→        second.insert("anyOf".to_owned(), Value::Array(branches));
1715→        preserved.insert(
1716→            "allOf".to_owned(),
1717→            Value::Array(vec![
1718→                Value::Object(sorted_object(first)),
1719→                Value::Object(sorted_object(second)),
1720→            ]),
1721→        );
1722→    } else {
1723→        preserved.insert("anyOf".to_owned(), Value::Array(branches));
1724→    }
1725→
1726→    *schema = sorted_object(preserved);
1727→    Ok(())
1728→}
