1748→fn collect_local_schema_refs_in_schema_object(
1749→    schema: &Map<String, Value>,
1750→    refs: &mut BTreeSet<String>,
1751→) {
1752→    for (key, value) in schema {
1753→        if matches!(key.as_str(), "$ref" | "$dynamicRef")
1754→            && let Some(reference) = value.as_str()
1755→            && let Some(reference) = normalize_local_ref_target(reference)
1756→        {
1757→            refs.insert(reference);
1758→        }
1759→
1760→        collect_local_schema_refs_in_keyword_value(key, value, refs);
