1764→fn collect_local_schema_refs_in_keyword_value(
1765→    key: &str,
1766→    value: &Value,
1767→    refs: &mut BTreeSet<String>,
1768→) {
1769→    match key {
1770→        "$schema"
1771→        | "$ref"
1772→        | "$dynamicRef"
1773→        | "required"
1774→        | "dependentRequired"
1775→        | "enum"
1776→        | "type"
1777→        | "const"
1778→        | "default"
1779→        | "examples"
1780→        | JSONCOMPAT_METADATA_KEY => {}
1781→        "not"
1782→        | "if"
1783→        | "then"
1784→        | "else"
1785→        | "contains"
1786→        | "additionalProperties"
1787→        | "propertyNames"
1788→        | "unevaluatedItems"
1789→        | "unevaluatedProperties"
1790→        | "contentSchema" => collect_local_schema_refs_in_schema_value(value, refs),
1791→        "items" => match value {
1792→            Value::Array(items) => {
1793→                for item in items {
1794→                    collect_local_schema_refs_in_schema_value(item, refs);
1795→                }
1796→            }
1797→            _ => collect_local_schema_refs_in_schema_value(value, refs),
1798→        },
1799→        "allOf" | "anyOf" | "oneOf" | "prefixItems" => {
1800→            if let Value::Array(items) = value {
1801→                for item in items {
1802→                    collect_local_schema_refs_in_schema_value(item, refs);
1803→                }
1804→            }
1805→        }
1806→        "properties" | "patternProperties" | "$defs" | "definitions" | "dependentSchemas" => {
1807→            if let Value::Object(entries) = value {
1808→                for child in entries.values() {
1809→                    collect_local_schema_refs_in_schema_value(child, refs);
1810→                }
1811→            }
1812→        }
1813→        _ => collect_local_schema_refs_in_unknown_keyword_value(value, refs),
1814→    }
1815→}
