1817→fn collect_local_schema_refs_in_unknown_keyword_value(value: &Value, refs: &mut BTreeSet<String>) {
1818→    match value {
1819→        Value::Object(_) | Value::Bool(_) => collect_local_schema_refs_in_schema_value(value, refs),
1820→        Value::Array(items) => {
1821→            for item in items {
1822→                collect_local_schema_refs_in_unknown_keyword_value(item, refs);
1823→            }
1824→        }
1825→        Value::Null | Value::Number(_) | Value::String(_) => {}
1826→    }
1827→}
