1839→fn normalize_local_ref_target(reference: &str) -> Option<String> {
1840→    if reference == "#" {
1841→        return Some(reference.to_owned());
1842→    }
1843→
1844→    let stripped = reference.strip_prefix("#/")?;
1845→    let mut normalized = String::from("#");
1846→    for token in stripped.split('/') {
1847→        let mut decoded = percent_decode_str(token).decode_utf8_lossy().into_owned();
1848→        decoded = decoded.replace("~1", "/");
1849→        decoded = decoded.replace("~0", "~");
1850→        normalized.push('/');
1851→        normalized.push_str(&escape_pointer_token(&decoded));
1852→    }
1853→    Some(normalized)
1854→}
