1859→            obj.contains_key("$id")
1860→                || obj.contains_key("$anchor")
1861→                || obj.contains_key("$dynamicAnchor")
1862→                || obj.values().any(schema_contains_resource_identifier)
1863→        }
1864→        Value::Array(items) => items.iter().any(schema_contains_resource_identifier),
1865→        _ => false,
1866→    }
