1869→fn rewrite_unsatisfiable_object(
1870→    schema: &Map<String, Value>,
1871→    pointer: &str,
1872→    local_ref_targets: &BTreeSet<String>,
1873→) -> Option<Value> {
1874→    if preserve_unknown_keyword_at_pointer(pointer, local_ref_targets) {
1875→        return None;
1876→    }
1877→
1878→    let type_name = schema.get("type").and_then(Value::as_str);
1879→    match type_name {
1880→        Some("string") => {
1881→            let min_length = schema.get("minLength").and_then(Value::as_u64).unwrap_or(0);
1882→            if let Some(max_length) = schema.get("maxLength").and_then(Value::as_u64)
1883→                && min_length > max_length
1884→            {
1885→                return Some(Value::Object(unsatisfiable_object(schema)));
1886→            }
1887→        }
1888→        Some("object") => {
1889→            let required_count = schema
1890→                .get("required")
1891→                .and_then(Value::as_array)
1892→                .map(Vec::len)
1893→                .unwrap_or(0);
1894→            let min_properties = schema
1895→                .get("minProperties")
1896→                .and_then(Value::as_u64)
1897→                .unwrap_or(required_count as u64);
1898→            if let Some(max_properties) = schema.get("maxProperties").and_then(Value::as_u64)
1899→                && min_properties > max_properties
1900→            {
1901→                return Some(Value::Object(unsatisfiable_object(schema)));
1902→            }
1903→        }
1904→        Some("array") => {
1905→            let min_items = schema.get("minItems").and_then(Value::as_u64).unwrap_or(0);
1906→            if let Some(max_items) = schema.get("maxItems").and_then(Value::as_u64)
1907→                && min_items > max_items
1908→            {
1909→                return Some(Value::Object(unsatisfiable_object(schema)));
1910→            }
1911→            if let (Some(min_contains), Some(max_contains)) = (
1912→                schema.get("minContains").and_then(Value::as_u64),
1913→                schema.get("maxContains").and_then(Value::as_u64),
1914→            ) && min_contains > max_contains
1915→            {
1916→                return Some(Value::Object(unsatisfiable_object(schema)));
1917→            }
1918→            if let (Some(min_contains), Some(max_items)) = (
1919→                schema.get("minContains").and_then(Value::as_u64),
1920→                schema.get("maxItems").and_then(Value::as_u64),
1921→            ) && min_contains > max_items
1922→            {
1923→                return Some(Value::Object(unsatisfiable_object(schema)));
1924→            }
1925→        }
1926→        Some("integer") => {
1927→            let min = schema.get("minimum").and_then(Value::as_i64);
1928→            let max = schema.get("maximum").and_then(Value::as_i64);
1929→            if let (Some(min), Some(max)) = (min, max)
1930→                && min > max
1931→            {
1932→                return Some(Value::Object(unsatisfiable_object(schema)));
1933→            }
1934→        }
1935→        Some("number") => {
1936→            let min = schema.get("minimum").and_then(Value::as_f64);
1937→            let max = schema.get("maximum").and_then(Value::as_f64);
1938→            if let (Some(min), Some(max)) = (min, max)
1939→                && min > max
1940→            {
1941→                return Some(Value::Object(unsatisfiable_object(schema)));
1942→            }
1943→        }
1944→        _ => {}
1945→    }
1946→    None
1947→}
