1949→fn fill_implicit_constraints(schema: &mut Map<String, Value>) {
1950→    match schema.get("type").and_then(Value::as_str) {
1951→        Some("object") => {
1952→            if !schema.contains_key("properties") {
1953→                schema.insert("properties".to_owned(), Value::Object(Map::new()));
1954→            }
1955→            if !schema.contains_key("minProperties") {
1956→                let min_properties = schema
1957→                    .get("required")
1958→                    .and_then(Value::as_array)
1959→                    .map(Vec::len)
1960→                    .unwrap_or(0);
1961→                schema.insert(
1962→                    "minProperties".to_owned(),
1963→                    Value::Number(Number::from(min_properties as u64)),
1964→                );
1965→            } else if let (Some(Value::Number(min_properties)), Some(Value::Array(required_values))) =
1966→                (schema.get("minProperties").cloned(), schema.get("required"))
1967→                && let Some(min_properties) = min_properties.as_u64()
1968→                && (required_values.len() as u64) > min_properties
1969→            {
1970→                schema.insert(
1971→                    "minProperties".to_owned(),
1972→                    Value::Number(Number::from(required_values.len() as u64)),
1973→                );
1974→            }
1975→        }
1976→        Some("array") => {
1977→            if !schema.contains_key("items") && !schema.contains_key("unevaluatedItems") {
1978→                schema.insert("items".to_owned(), Value::Bool(true));
1979→            }
1980→            if !schema.contains_key("minItems") {
1981→                let min_items = if schema.contains_key("contains") {
1982→                    schema
1983→                        .get("minContains")
1984→                        .and_then(Value::as_u64)
1985→                        .unwrap_or(1)
1986→                } else {
1987→                    0
1988→                };
1989→                schema.insert(
1990→                    "minItems".to_owned(),
1991→                    Value::Number(Number::from(min_items)),
1992→                );
1993→            }
1994→            if let (Some(max_contains), Some(max_items)) = (
1995→                schema.get("maxContains").and_then(Value::as_u64),
1996→                schema.get("maxItems").and_then(Value::as_u64),
1997→            ) && max_contains > max_items
1998→            {
1999→                schema.insert(
2000→                    "maxContains".to_owned(),
2001→                    Value::Number(Number::from(max_items)),
2002→                );
2003→            }
2004→        }
2005→        Some("string") => {
2006→            schema
2007→                .entry("minLength".to_owned())
2008→                .or_insert_with(|| Value::Number(Number::from(0_u64)));
2009→        }
2010→        Some("integer") => {
2011→            schema
2012→                .entry("multipleOf".to_owned())
2013→                .or_insert_with(|| Value::Number(Number::from(1_u64)));
2014→        }
2015→        _ => {}
2016→    }
2017→}
