2019→fn value_matches_type(value: &Value, type_value: &Value) -> bool {
2020→    match type_value {
2021→        Value::String(type_name) => primitive_type_set(type_name).is_some_and(|types| {
2022→            value_type_name(value).is_some_and(|value_type| types.contains(value_type))
2023→        }),
2024→        Value::Array(items) => items.iter().any(|item| value_matches_type(value, item)),
2025→        _ => false,
2026→    }
2027→}
2028→
2029→fn value_is_multiple_of(
2030→    value: &Value,
2031→    multiple_of: &Value,
2032→    type_name: &str,
2033→    value_pointer: &str,
2034→    multiple_of_pointer: &str,
2035→) -> Result<bool> {
2036→    match type_name {
2037→        "integer" => {
2038→            let value = integer_value_from_json(value, value_pointer)?;
2039→            let multiple_of = integer_value_from_json(multiple_of, multiple_of_pointer)?;
2040→            Ok(multiple_of != 0 && value % multiple_of == 0)
2041→        }
2042→        "number" => {
2043→            let Some(value) = value.as_f64() else {
2044→                return Err(CanonicalizeError::NonFiniteNumericKeyword {
2045→                    pointer: value_pointer.to_owned(),
2046→                    keyword: last_pointer_token(value_pointer),
2047→                });
2048→            };
2049→            let Some(multiple_of) = multiple_of.as_f64() else {
2050→                return Err(CanonicalizeError::NonFiniteNumericKeyword {
2051→                    pointer: multiple_of_pointer.to_owned(),
2052→                    keyword: last_pointer_token(multiple_of_pointer),
2053→                });
2054→            };
2055→            if multiple_of == 0.0 {
2056→                return Ok(false);
2057→            }
2058→            let quotient = value / multiple_of;
2059→            Ok((quotient - quotient.round()).abs() <= f64::EPSILON * quotient.abs().max(1.0) * 4.0)
2060→        }
2061→        _ => Ok(true),
2062→    }
2063→}
2064→
2065→fn integer_value_from_json(value: &Value, pointer: &str) -> Result<i64> {
2066→    let Some(number) = value.as_number() else {
2067→        return Err(CanonicalizeError::IntegerKeywordOutOfRange {
2068→            pointer: pointer.to_owned(),
2069→            keyword: last_pointer_token(pointer),
2070→        });
2071→    };
2072→    if let Some(value) = number.as_i64() {
2073→        return Ok(value);
2074→    }
2075→    if let Some(value) = number.as_u64() {
2076→        return checked_i64_from_u64(value, pointer);
2077→    }
2078→    Err(CanonicalizeError::IntegerKeywordOutOfRange {
2079→        pointer: pointer.to_owned(),
2080→        keyword: last_pointer_token(pointer),
2081→    })
2082→}
2083→
2084→fn checked_i64_from_u64(value: u64, pointer: &str) -> Result<i64> {
2085→    i64::try_from(value).map_err(|_| CanonicalizeError::IntegerKeywordOutOfRange {
2086→        pointer: pointer.to_owned(),
2087→        keyword: last_pointer_token(pointer),
2088→    })
2089→}
