    fn value_type_name_treats_integral_json_numbers_as_integer() {
        assert_eq!(value_type_name(&json!(1.0)), Some(PrimitiveType::Integer));
        assert_eq!(value_type_name(&json!(1.5)), Some(PrimitiveType::Number));
    }
